            UPGRADEABLE_READER | BEING_UPGRADED,
            WRITER | UPGRADEABLE_READER,
            AcqRel,
            Relaxed,
        );
        if res.is_ok() {
            let inner = self.inner;
            let guard = self.guard.transfer_to();
            drop(self);
            Ok(RwLockWriteGuard { inner, guard })
        } else {
            Err(self)
        }
    }
}

