+#[derive(Clone, Debug, PartialEq, Eq)]
+struct BlockState<'tcx> {
+    aliases: BTreeMap<Local, Place<'tcx>>,
+    guards: BTreeMap<Local, LockInfoArtifact>,
+}
+
+impl<'tcx> BlockState<'tcx> {
+    fn empty() -> Self {
+        Self {
+            aliases: BTreeMap::new(),
+            guards: BTreeMap::new(),
+        }
+    }
+}
