+#[derive(Clone, Debug)]
+enum CallEffect<'tcx> {
+    Alias { destination: Local, source: Place<'tcx> },
+    Acquire {
+        destination: Local,
+        lock: LockInfoArtifact,
+    },
+    Release {
+        local: Local,
+    },
+}
