+fn analyze_body<'tcx>(
+    tcx: TyCtxt<'tcx>,
+    body: &Body<'tcx>,
+) -> (Vec<LockEventArtifact>, Vec<LockEdgeArtifact>) {
+    let in_states = compute_block_states(tcx, body);
+    let mut events = Vec::new();
+    let mut edges = Vec::new();
+
+    for (block, block_data) in body.basic_blocks.iter_enumerated() {
+        let mut state = in_states[block].clone().unwrap_or_else(BlockState::empty);
+
+        for statement in &block_data.statements {
+            apply_statement(tcx, body, &mut state, statement.kind.as_assign());
+
+            if let StatementKind::StorageDead(local) = statement.kind {
+                release_guard(&mut state, local, statement.kind.name());
+            }
+        }
+
+        if let Some(terminator) = &block_data.terminator {
+            if let Some(effect) = classify_call_effect(tcx, body, terminator.kind.as_call()) {
+                apply_effect(&mut state, &effect);
+                emit_effect(
+                    &mut events,
+                    &mut edges,
+                    &state,
+                    effect,
+                    span_to_location(tcx, terminator.source_info.span),
+                );
+            } else if let TerminatorKind::Drop { place, .. } = &terminator.kind
+                && let Some(local) = place.as_local()
+            {
+                if let Some(lock) = state.guards.get(&local).cloned() {
+                    events.push(LockEventArtifact {
+                        kind: "release".into(),
+                        lock,
+                        guard_local: Some(format_local(body, local)),
+                        location: span_to_location(tcx, terminator.source_info.span),
+                    });
+                }
+                release_guard(&mut state, local, "Drop");
+            }
+        }
+    }
+
+    dedup_edges(&mut edges);
+    (events, edges)
+}
+
+fn compute_block_states<'tcx>(
+    tcx: TyCtxt<'tcx>,
+    body: &Body<'tcx>,
+) -> Vec<Option<BlockState<'tcx>>> {
+    let mut in_states = vec![None; body.basic_blocks.len()];
+    in_states[BasicBlock::from_usize(0).as_usize()] = Some(BlockState::empty());
+
+    let predecessors = body.basic_blocks.predecessors().clone();
+    let mut queue = VecDeque::from([BasicBlock::from_usize(0)]);
+
+    while let Some(block) = queue.pop_front() {
+        let mut state = in_states[block.as_usize()]
+            .clone()
+            .unwrap_or_else(BlockState::empty);
+
+        let block_data = &body[block];
+        for statement in &block_data.statements {
+            apply_statement(tcx, body, &mut state, statement.kind.as_assign());
+            if let StatementKind::StorageDead(local) = statement.kind {
+                release_guard(&mut state, local, statement.kind.name());
+            }
+        }
+
+        if let Some(terminator) = &block_data.terminator {
+            if let Some(effect) = classify_call_effect(tcx, body, terminator.kind.as_call()) {
+                apply_effect(&mut state, &effect);
+            } else if let TerminatorKind::Drop { place, .. } = &terminator.kind
+                && let Some(local) = place.as_local()
+            {
+                release_guard(&mut state, local, "Drop");
+            }
+
+            for successor in terminator.successors() {
+                let joined = if let Some(existing) = &in_states[successor.as_usize()] {
+                    join_states(existing, &state)
+                } else if predecessors[successor].len() <= 1 {
+                    state.clone()
+                } else {
+                    let pred_states = predecessors[successor]
+                        .iter()
+                        .filter_map(|predecessor| in_states[predecessor.as_usize()].as_ref());
+                    join_many_states(pred_states).unwrap_or_else(BlockState::empty)
+                };
+
+                if in_states[successor.as_usize()].as_ref() != Some(&joined) {
+                    in_states[successor.as_usize()] = Some(joined);
+                    queue.push_back(successor);
+                }
+            }
+        }
+    }
+
+    in_states
+}
+
+fn apply_statement<'tcx>(
+    tcx: TyCtxt<'tcx>,
+    body: &Body<'tcx>,
+    state: &mut BlockState<'tcx>,
+    assign: Option<&(Place<'tcx>, rustc_middle::mir::Rvalue<'tcx>)>,
+) {
+    let Some((place, rvalue)) = assign else {
+        return;
+    };
+    let Some(local) = place.as_local() else {
+        return;
+    };
+
+    state.aliases.remove(&local);
+    state.guards.remove(&local);
+
+    match rvalue {
+        rustc_middle::mir::Rvalue::Ref(_, _, source) => {
+            state.aliases.insert(local, resolve_alias(state, *source));
+        }
+        rustc_middle::mir::Rvalue::Use(operand) => {
+            if let Some(source) = operand.place() {
+                let source = resolve_alias(state, source);
+                if source.as_local().is_some() {
+                    state.aliases.insert(local, source);
+                }
+            }
+        }
+        rustc_middle::mir::Rvalue::Cast(_, operand, _) => {
+            if let Some(source) = operand.place() {
+                let source = resolve_alias(state, source);
+                if source.as_local().is_some() {
+                    state.aliases.insert(local, source);
+                }
+            }
+        }
+        _ => {
+            let _ = tcx;
+            let _ = body;
+        }
+    }
+}
+
+fn classify_call_effect<'tcx>(
+    tcx: TyCtxt<'tcx>,
+    body: &Body<'tcx>,
+    call: Option<&rustc_middle::mir::TerminatorKind<'tcx>>,
+) -> Option<CallEffect<'tcx>> {
+    let rustc_middle::mir::TerminatorKind::Call {
+        func,
+        args,
+        destination,
+        ..
+    } = call?
+    else {
+        return None;
+    };
+
+    let (def_id, _) = func.const_fn_def()?;
+    let method_name = tcx.item_name(def_id).as_str();
+
+    if method_name == "drop" {
+        let local = args.first()?.node.place()?.as_local()?;
+        return Some(CallEffect::Release { local });
+    }
+
+    let receiver = args.first()?.node.place()?;
+    let destination = destination.as_local()?;
+
+    if method_name == "disable_irq" {
+        return Some(CallEffect::Alias {
+            destination,
+            source: receiver,
+        });
+    }
+
+    let receiver_ty = args.first()?.node.ty(body, tcx);
+    let lock = classify_lock_call(tcx, receiver, receiver_ty, method_name)?;
+    if matches!(lock.acquire.as_str(), "try_lock" | "try_read" | "try_write") {
+        return None;
+    }
+
+    Some(CallEffect::Acquire { destination, lock })
+}
+
+fn classify_lock_call<'tcx>(
+    tcx: TyCtxt<'tcx>,
+    receiver: Place<'tcx>,
+    receiver_ty: Ty<'tcx>,
+    method_name: &str,
+) -> Option<LockInfoArtifact> {
+    let lock_ty = peel_refs(receiver_ty);
+    let ty::Adt(adt, args) = lock_ty.kind() else {
+        return None;
+    };
+    let primitive = tcx.item_name(adt.did()).to_string();
+
+    let acquire = match (&*primitive, method_name) {
+        ("SpinLock", "lock" | "try_lock")
+        | ("RwLock", "read" | "write" | "try_read" | "try_write")
+        | ("Mutex", "lock" | "try_lock")
+        | ("RwMutex", "read" | "write" | "try_read" | "try_write") => method_name.to_string(),
+        _ => return None,
+    };
+
+    let guard_behavior = guard_behavior_for_call(tcx, adt, args, method_name);
+    Some(LockInfoArtifact {
+        class: format!("{receiver:?}"),
+        primitive,
+        acquire,
+        guard_behavior,
+    })
+}
+
+fn guard_behavior_for_call<'tcx>(
+    tcx: TyCtxt<'tcx>,
+    adt: AdtDef<'tcx>,
+    args: GenericArgsRef<'tcx>,
+    method_name: &str,
+) -> String {
+    let primitive = tcx.item_name(adt.did()).as_str();
+    if primitive == "Mutex" || primitive == "RwMutex" {
+        return "Sleeping".into();
+    }
+
+    let guardian = args
+        .types()
+        .nth(1)
+        .map(|ty| short_type_name(tcx, peel_refs(ty)))
+        .unwrap_or_else(|| "Unknown".into());
+
+    if primitive == "RwLock" && guardian == "WriteIrqDisabled" && method_name == "read" {
+        "PreemptDisabled".into()
+    } else {
+        guardian
+    }
+}
+
+fn apply_effect<'tcx>(state: &mut BlockState<'tcx>, effect: &CallEffect<'tcx>) {
+    match effect {
+        CallEffect::Alias {
+            destination,
+            source,
+        } => {
+            state.aliases.insert(*destination, *source);
+            state.guards.remove(destination);
+        }
+        CallEffect::Acquire { destination, lock } => {
+            state.guards.insert(*destination, lock.clone());
+            state.aliases.remove(destination);
+        }
+        CallEffect::Release { local } => {
+            state.guards.remove(local);
+            state.aliases.remove(local);
+        }
+    }
+}
+
+fn emit_effect(
+    events: &mut Vec<LockEventArtifact>,
+    edges: &mut Vec<LockEdgeArtifact>,
+    state: &BlockState<'_>,
+    effect: CallEffect<'_>,
+    location: Option<SourceLocation>,
+) {
+    match effect {
+        CallEffect::Alias { .. } => {}
+        CallEffect::Acquire { destination, lock } => {
+            for held in state.guards.values() {
+                if held.class != lock.class {
+                    edges.push(LockEdgeArtifact {
+                        from: held.clone(),
+                        to: lock.clone(),
+                        location: location.clone(),
+                    });
+                }
+            }
+
+            events.push(LockEventArtifact {
+                kind: "acquire".into(),
+                lock,
+                guard_local: Some(destination.as_usize().to_string()),
+                location,
+            });
+        }
+        CallEffect::Release { local } => {
+            if let Some(lock) = state.guards.get(&local).cloned() {
+                events.push(LockEventArtifact {
+                    kind: "release".into(),
+                    lock,
+                    guard_local: Some(local.as_usize().to_string()),
+                    location,
+                });
+            }
+        }
+    }
+}
+
+fn join_many_states<'tcx>(
+    mut states: impl Iterator<Item = &'tcx BlockState<'tcx>>,
+) -> Option<BlockState<'tcx>> {
+    let first = states.next()?.clone();
+    Some(states.fold(first, |joined, state| join_states(&joined, state)))
+}
+
+fn join_states<'tcx>(left: &BlockState<'tcx>, right: &BlockState<'tcx>) -> BlockState<'tcx> {
+    let aliases = left
+        .aliases
+        .iter()
+        .filter_map(|(local, place)| {
+            right
+                .aliases
+                .get(local)
+                .filter(|other| *other == place)
+                .map(|_| (*local, *place))
+        })
+        .collect();
+    let guards = left
+        .guards
+        .iter()
+        .filter_map(|(local, lock)| {
+            right
+                .guards
+                .get(local)
+                .filter(|other| *other == lock)
+                .map(|_| (*local, lock.clone()))
+        })
+        .collect();
+
+    BlockState { aliases, guards }
+}
+
+fn release_guard<'tcx>(state: &mut BlockState<'tcx>, local: Local, _reason: &str) {
+    state.guards.remove(&local);
+    state.aliases.remove(&local);
+}
+
+fn resolve_alias<'tcx>(state: &BlockState<'tcx>, place: Place<'tcx>) -> Place<'tcx> {
+    let Some(local) = place.as_local() else {
+        return place;
+    };
+    state.aliases.get(&local).copied().unwrap_or(place)
+}
+
+fn dedup_edges(edges: &mut Vec<LockEdgeArtifact>) {
+    let mut seen = BTreeSet::new();
+    edges.retain(|edge| {
+        seen.insert((
+            edge.from.class.clone(),
+            edge.from.acquire.clone(),
+            edge.to.class.clone(),
+            edge.to.acquire.clone(),
+            edge.location.as_ref().map(|location| {
+                (location.file.clone(), location.line, location.column)
+            }),
+        ))
+    });
+}
+
+fn peel_refs<'tcx>(mut ty: Ty<'tcx>) -> Ty<'tcx> {
+    while let ty::Ref(_, inner, _) = ty.kind() {
+        ty = *inner;
+    }
+    ty
+}
+
+fn short_type_name<'tcx>(tcx: TyCtxt<'tcx>, ty: Ty<'tcx>) -> String {
+    match ty.kind() {
+        ty::Adt(def, _) => tcx.item_name(def.did()).to_string(),
+        _ => ty.to_string(),
+    }
+}
+
+fn span_to_location<'tcx>(tcx: TyCtxt<'tcx>, span: rustc_span::Span) -> Option<SourceLocation> {
+    if span.is_dummy() {
+        return None;
+    }
+
+    let source_map = tcx.sess.source_map();
+    let location = source_map.lookup_char_pos(span.lo());
+    Some(SourceLocation {
+        file: location.file.name.prefer_local().to_string(),
+        line: location.line,
+        column: location.col_display + 1,
+    })
+}
+
+trait TerminatorKindExt<'tcx> {
+    fn as_call(&self) -> Option<&rustc_middle::mir::TerminatorKind<'tcx>>;
+}
+
+impl<'tcx> TerminatorKindExt<'tcx> for TerminatorKind<'tcx> {
+    fn as_call(&self) -> Option<&rustc_middle::mir::TerminatorKind<'tcx>> {
+        matches!(self, TerminatorKind::Call { .. }).then_some(self)
+    }
+}
+
+fn format_local<'tcx>(body: &Body<'tcx>, local: Local) -> String {
+    if local.as_usize() == 0 {
+        return "return".into();
+    }
+    if local.as_usize() <= body.arg_count {
+        return format!("arg{}", local.as_usize());
+    }
+    format!("_{}", local.as_usize())
+}
