        on_stack: BTreeSet<usize>,
        indices: BTreeMap<usize, usize>,
        lowlinks: BTreeMap<usize, usize>,
        components: Vec<Vec<usize>>,
    }

    fn strong_connect(
        node: usize,
        adjacency: &BTreeMap<usize, BTreeSet<usize>>,
        state: &mut TarjanState,
    ) {
