fn find_irq_conflicts(crates: &[AnalysisArtifact]) -> Vec<IrqConflictReport> {
    let mut interrupt_sites = BTreeMap::<LockInfoArtifact, Vec<IrqUseSite>>::new();
    let mut interruptible_sites = BTreeMap::<LockInfoArtifact, Vec<IrqUseSite>>::new();

    for crate_artifact in crates {
        for function in &crate_artifact.functions {
            for event in function
                .lock_events
                .iter()
                .filter(|event| event.kind == "acquire")
            {
                let site = IrqUseSite {
                    crate_name: crate_artifact.package_name.clone(),
                    function: function.def_path.clone(),
                    context: event.context.clone(),
                    location: event.location.clone(),
                };

                if is_interrupt_context(&event.context) {
                    interrupt_sites
                        .entry(event.lock.clone())
                        .or_default()
                        .push(site.clone());
                }
                if is_interruptible_context(&event.context) {
                    interruptible_sites
                        .entry(event.lock.clone())
                        .or_default()
                        .push(site);
                }
            }
        }
    }

    let mut conflicts = Vec::new();
    for (lock, interrupt_sites_for_lock) in &interrupt_sites {
        let Some(interruptible_sites_for_lock) = interruptible_sites.get(lock) else {
            continue;
        };
        conflicts.push(IrqConflictReport {
            lock: lock.clone(),
            interrupt_sites: interrupt_sites_for_lock.clone(),
            interruptible_sites: interruptible_sites_for_lock.clone(),
        });
    }

    conflicts
}

