fn trace_lock_call(method_name: &str, callee_path: &str, receiver_ty: Ty<'_>, matched: bool) {
    if env::var_os("LOCKDEP_TRACE_CALLS").is_none() {
        return;
    }
    if matches!(
        method_name,
        "lock" | "read" | "write" | "try_lock" | "try_read" | "try_write" | "disable_irq"
    ) {
        eprintln!(
            "lockdep trace: method={method_name} matched={matched} callee={callee_path} receiver_ty={receiver_ty}",
        );
    }
}

fn classify_lock_call<'tcx>(
    tcx: TyCtxt<'tcx>,
    current_def_id: DefId,
    body: &Body<'tcx>,
    receiver: Place<'tcx>,
    receiver_ty: Ty<'tcx>,
    method_name: &str,
) -> Option<LockInfoArtifact> {
    let lock_ty = peel_refs(receiver_ty);
    let ty::Adt(adt, args) = lock_ty.kind() else {
        return None;
    };
    let primitive = tcx.item_name(adt.did()).to_string();

    let acquire = match (&*primitive, method_name) {
        ("SpinLock", "lock" | "try_lock")
        | ("RwLock", "read" | "write" | "try_read" | "try_write")
        | ("Mutex", "lock" | "try_lock")
        | ("RwMutex", "read" | "write" | "try_read" | "try_write") => method_name.to_string(),
        _ => return None,
    };

    let guard_behavior = guard_behavior_for_call(tcx, *adt, args, method_name);
    Some(LockInfoArtifact {
        class: lock_class_key(tcx, current_def_id, body, receiver),
        primitive,
        acquire,
        guard_behavior,
    })
}

fn guard_behavior_for_call<'tcx>(
    tcx: TyCtxt<'tcx>,
    adt: AdtDef<'tcx>,
    args: GenericArgsRef<'tcx>,
    method_name: &str,
) -> String {
    let item_name = tcx.item_name(adt.did());
    let primitive = item_name.as_str();
    if primitive == "Mutex" || primitive == "RwMutex" {
        return "Sleeping".into();
    }

    let guardian = args
        .types()
        .nth(1)
        .map(|ty| short_type_name(tcx, peel_refs(ty)))
        .unwrap_or_else(|| "Unknown".into());

    if primitive == "RwLock" && guardian == "WriteIrqDisabled" && method_name == "read" {
        "PreemptDisabled".into()
    } else {
        guardian
    }
}

fn apply_effect<'tcx>(state: &mut BlockState<'tcx>, effect: &CallEffect<'tcx>) {
    match effect {
        CallEffect::Alias {
            destination,
            source,
        } => {
            state.aliases.insert(*destination, resolve_alias(state, *source));
            state.guards.remove(destination);
        }
        CallEffect::Acquire { destination, lock } => {
            state.guards.insert(*destination, lock.clone());
            state.aliases.remove(destination);
        }
        CallEffect::Release { local } => {
            state.guards.remove(local);
            state.aliases.remove(local);
            state.irq_guard_locals.remove(local);
        }
    }
}

fn emit_effect(
    events: &mut Vec<LockEventArtifact>,
    edges: &mut Vec<LockEdgeArtifact>,
    entry_locks: &mut BTreeSet<LockInfoArtifact>,
    body: &Body<'_>,
    state: &BlockState<'_>,
    base_context: ContextKind,
    effect: CallEffect<'_>,
    location: Option<SourceLocation>,
) {
    match effect {
        CallEffect::Alias { .. } => {}
        CallEffect::Acquire { destination, lock } => {
            let context = context_for_acquire(state, base_context, &lock)
                .as_str()
                .to_string();
            if state.guards.is_empty() {
                entry_locks.insert(lock.clone());
            }
            for held in state.guards.values() {
                if held.class != lock.class {
                    edges.push(LockEdgeArtifact {
                        context: context.clone(),
                        from: held.clone(),
                        to: lock.clone(),
                        location: location.clone(),
                    });
                }
            }

            events.push(LockEventArtifact {
                kind: "acquire".into(),
                context,
                lock,
                guard_local: Some(format_local(body, destination)),
                location,
            });
        }
        CallEffect::Release { local } => {
            if let Some(lock) = state.guards.get(&local).cloned() {
                events.push(LockEventArtifact {
                    kind: "release".into(),
                    context: current_context(state, base_context).as_str().to_string(),
                    lock,
                    guard_local: Some(format_local(body, local)),
                    location,
                });
            }
        }
    }
}

fn collect_callsite<'tcx>(
    tcx: TyCtxt<'tcx>,
    state: &BlockState<'tcx>,
    base_context: ContextKind,
    call: Option<&rustc_middle::mir::TerminatorKind<'tcx>>,
    location: Option<SourceLocation>,
) -> Option<CallSite> {
    let rustc_middle::mir::TerminatorKind::Call { func, .. } = call? else {
        return None;
    };
    let (callee, _) = func.const_fn_def()?;
    if !callee.is_local() || !tcx.def_kind(callee).is_fn_like() {
        return None;
    }

    Some(CallSite {
        callee,
        held_locks: state.guards.values().cloned().collect(),
        context: current_context(state, base_context),
        location,
    })
}

fn compute_summary_entry_locks(
    analyses: &[FunctionAnalysis],
) -> HashMap<DefId, BTreeSet<LockInfoArtifact>> {
    let mut summaries = analyses
        .iter()
        .map(|analysis| (analysis.def_id, analysis.entry_locks.clone()))
        .collect::<HashMap<_, _>>();

    let mut changed = true;
    while changed {
        changed = false;
        for analysis in analyses {
            let mut merged = summaries
                .get(&analysis.def_id)
                .cloned()
                .unwrap_or_default();
            for callsite in analysis.callsites.iter().filter(|callsite| callsite.held_locks.is_empty())
            {
                if let Some(callee_locks) = summaries.get(&callsite.callee) {
                    let previous_len = merged.len();
                    merged.extend(callee_locks.iter().cloned());
                    changed |= merged.len() != previous_len;
                }
            }
            summaries.insert(analysis.def_id, merged);
        }
    }

    summaries
}

