fn format_cycle(cycle: &CycleReport) -> String {
    if cycle.steps.is_empty() {
        return "<empty>".into();
    }

    let mut parts = Vec::new();
    parts.push(short_lock_label(&cycle.steps[0].from));
    for step in &cycle.steps {
        parts.push(short_lock_label(&step.to));
    }
    parts.join(" -> ")
}

fn short_lock_label(lock: &LockInfoArtifact) -> String {
    format!("{}({})", lock.primitive, lock.acquire)
}

fn find_irq_conflicts(crates: &[AnalysisArtifact]) -> Vec<IrqConflictReport> {
    let mut interrupt_sites = BTreeMap::<(String, String), Vec<IrqUseSite>>::new();
    let mut interruptible_sites = BTreeMap::<(String, String), Vec<IrqUseSite>>::new();

    for crate_artifact in crates {
        for function in &crate_artifact.functions {
            for event in function
                .lock_events
                .iter()
                .filter(|event| event.kind == "acquire")
            {
                let site = IrqUseSite {
                    crate_name: crate_artifact.package_name.clone(),
                    function: function.def_path.clone(),
                    context: event.context.clone(),
                    acquire: event.lock.acquire.clone(),
                    location: event.location.clone(),
                };
                let key = (event.lock.class.clone(), event.lock.primitive.clone());

                if is_interrupt_context(&event.context) {
                    interrupt_sites
                        .entry(key.clone())
                        .or_default()
                        .push(site.clone());
                }
                if is_interruptible_context(&event.context) {
                    interruptible_sites.entry(key).or_default().push(site);
                }
            }
        }
    }

    let mut conflicts = Vec::new();
    for ((class, primitive), interrupt_sites_for_lock) in &interrupt_sites {
        let Some(interruptible_sites_for_lock) =
            interruptible_sites.get(&(class.clone(), primitive.clone()))
        else {
            continue;
        };
        let has_conflicting_modes = interrupt_sites_for_lock.iter().any(|interrupt_site| {
            interruptible_sites_for_lock
                .iter()
                .any(|interruptible_site| {
                    irq_modes_conflict(
                        primitive,
                        &interrupt_site.acquire,
                        &interruptible_site.acquire,
                    )
                })
        });
        if !has_conflicting_modes {
            continue;
        }
        conflicts.push(IrqConflictReport {
            class: class.clone(),
            primitive: primitive.clone(),
            interrupt_sites: interrupt_sites_for_lock.clone(),
            interruptible_sites: interruptible_sites_for_lock.clone(),
        });
    }

    conflicts
}

fn is_interrupt_context(context: &str) -> bool {
    matches!(context, "HardIrqTopHalf" | "BottomHalfL2")
}

fn is_interruptible_context(context: &str) -> bool {
    matches!(context, "Task" | "BottomHalfL1")
}

fn irq_modes_conflict(primitive: &str, left: &str, right: &str) -> bool {
    match primitive {
        "RwLock" | "RwMutex" => !(left == "read" && right == "read"),
        _ => true,
    }
}

fn format_site_location(location: Option<&SourceLocation>) -> String {
    location
        .map(|location| format!("at {}:{}:{}", location.file, location.line, location.column))
        .unwrap_or_else(|| "at <unknown>".into())
}

fn is_deadlock_relevant_edge(from: &LockInfoArtifact, to: &LockInfoArtifact) -> bool {
    !(is_shared_read_lock(from) && is_shared_read_lock(to))
